function normalizeInnerQuotes(s) {
  if (!s || typeof s !== "string") return s;

  s = s.replace(/[״”“]/g, '"');
  s = s.replace(/([\u0590-\u05FF0-9A-Za-z])"(?=[\u0590-\u05FF0-9A-Za-z])/g, "$1״");
  s = s.replace(/[\u202A-\u202E\u2066-\u2069]/g, "");
  return s;
}

function makeFilenameSafe(s) {
  if (!s) return "";
  return String(s)
    .normalize("NFKD")
    .replace(/[^\p{L}\p{N}\s]+/gu, "")
    .trim()
    .replace(/\s+/g, "_")
    .replace(/-+/g, "");
}

const raw = $json.output ?? $json;
let plan = raw;
if (typeof raw === "string") {
  // Remove markdown code fences, e.g. ```json or ```
  const removeFences = s => s.replace(/```(?:json)?|```/gi, '').trim();
  const cleaned = normalizeInnerQuotes(removeFences(raw));
  plan = JSON.parse(cleaned);
}

// ✅ IMPORTANT: handle array wrapper: [ { hero, sections } ]
if (Array.isArray(plan)) {
  plan = plan[0] || {};
}

const out = [];

// HERO
if (plan?.hero?.prompt && String(plan.hero.prompt).trim()) {
  out.push({
    json: {
      slot: "hero",
      type: plan.hero.type || "hero",
      prompt: plan.hero.prompt,
      source_text: plan.hero.source_text || "",
      translation_en: plan.hero.translation_en || "",
      h2_text: "",
      alt: plan.hero.source_text || "",
      filename_safe:
        plan.hero.filename_safe ||
        makeFilenameSafe(plan.hero.translation_en || plan.hero.source_text || "hero"),
    },
  });
}

// SECTIONS
(plan?.sections || [])
  .filter(s => s?.prompt && String(s.prompt).trim())
  .forEach((s, i) => {
    out.push({
      json: {
        slot: `section_${i + 1}`,
        type: s.type || "section",
        prompt: s.prompt,
        h2_text: s.h2_text || "",
        source_text: s.source_text || "",
        translation_en: s.translation_en || "",
        alt: s.h2_text || s.source_text || "",
        filename_safe:
          s.filename_safe ||
          makeFilenameSafe(s.translation_en || s.h2_text || `section_${i + 1}`),
      },
    });
  });

return out;

// Parse the kie.ai polling response and decide whether to keep polling or stop.
// Fixes:
//  1) When Poll Task Status returns a non-200 (neverError:true), previous code
//     fell into the 'still processing' branch and looped forever. Now we bail out.
//  2) Added an elapsed-time timeout (read from Extract Task ID) so a task that
//     never finishes still exits the loop.
//  3) Forward taskId safely even when the poll response is empty/garbage.

const response = $json || {};

// Try to recover context set by the Extract Task ID node (same item branch)
let ctxTaskId = null;
let startedAt = Date.now();
let maxElapsedMs = 5 * 60 * 1000;
try {
  const ctx = $('Extract Task ID').item.json;
  ctxTaskId     = ctx.taskId     || ctxTaskId;
  startedAt     = ctx.startedAt  || startedAt;
  maxElapsedMs  = ctx.maxElapsedMs || maxElapsedMs;
} catch (e) { /* first run or unreachable - fall back to defaults */ }

const taskId = (response.data && response.data.taskId) || ctxTaskId || '';
const apiCode = response.code;
const apiMsg  = response.msg || response.message || '';

// --- 1) API-level error -> stop, do NOT re-enter the polling loop
if (apiCode !== undefined && apiCode !== 200 && apiCode !== 0) {
  return [{ json: {
    imageUrl: null, state: 'api_error', taskId,
    done: true, error: `kie.ai API error ${apiCode}: ${apiMsg}`
  }}];
}

const data  = response.data || {};
const state = data.state || 'unknown';

// --- 2) Success
if (state === 'success') {
  let imageUrl = null;
  if (data.resultJson) {
    try {
      const parsed = JSON.parse(data.resultJson);
      if (Array.isArray(parsed.resultUrls) && parsed.resultUrls.length > 0) {
        imageUrl = parsed.resultUrls[0];
      }
    } catch (e) {
      return [{ json: {
        imageUrl: null, state: 'parse_error', taskId,
        done: true, error: 'Could not parse resultJson: ' + e.message
      }}];
    }
  }
  return [{ json: { imageUrl, state: 'success', taskId, done: true } }];
}

// --- 3) Explicit failure
if (state === 'fail') {
  return [{ json: {
    imageUrl: null, state: 'fail', taskId,
    done: true, error: data.failMsg || 'Image generation failed'
  }}];
}

// --- 4) Safety net: no usable data AND unknown state -> stop, don't loop forever
if (state === 'unknown' && !data.taskId && !data.state) {
  return [{ json: {
    imageUrl: null, state: 'invalid_response', taskId,
    done: true,
    error: 'Invalid polling response: ' + JSON.stringify(response).substring(0, 200)
  }}];
}

// --- 5) Elapsed-time timeout
const elapsed = Date.now() - startedAt;
if (elapsed > maxElapsedMs) {
  return [{ json: {
    imageUrl: null, state: 'timeout', taskId,
    done: true, error: `Timed out after ${Math.round(elapsed/1000)}s while polling kie.ai`
  }}];
}

// --- 6) Still processing (waiting / queuing / generating) -> poll again
return [{ json: { taskId, state, done: false } }];

const items = $items();
const urls = items.map(i => i.json["Image URL"]).filter(Boolean);

const images = {
  hero: urls[0] || null,
  section_1: urls[1] || null,
  section_2: urls[2] || null,
  section_3: urls[3] || null,
  section_4: urls[4] || null,
};

return [{ json: { images } }];

// Build image upload items where filename_safe comes from translation_en
// (pulled from "Cleaning Image Prompts" node by matching slot).

function cleanHeadingText(s) {
  if (!s) return "";
  return String(s)
    .replace(/<[^>]*>/g, "")
    .replace(/^#+\s*/g, "")
    .replace(/^\d+[\.\)]\s*/g, "")
    .trim();
}

function extractHeadingsFromMarkdown(md) {
  const lines = (md || "").split("\n");
  let h1 = "";
  const h2 = [];

  for (const rawLine of lines) {
    const line = rawLine.trim();

    const m1 = line.match(/^#\s+(.+)$/);
    if (m1 && !h1) {
      h1 = cleanHeadingText(m1[1]);
      continue;
    }

    const m2 = line.match(/^##\s*(.+)$/);
    if (m2) {
      const txt = cleanHeadingText(m2[1]);
      if (txt) h2.push(txt);
    }
  }

  return { h1, h2 };
}

/**
 * ✅ STRICT HEADER-SAFE FILENAME
 * - NO hyphens
 * - NO spaces
 * - NO extension
 * - ASCII only
 */
function toHeaderSafeFilename(str) {
  const s = String(str || "")
    .trim()
    .replace(/\.(png|jpg|jpeg|webp|gif)$/i, "") // strip extension if present
    .normalize("NFKD")
    .replace(/[\u00A0\u2000-\u200B\u202F\u205F\u3000]/g, "") // remove weird spaces
    .replace(/[\u0300-\u036f]/g, "") // accents
    .replace(/[—–]/g, "")           // long dashes
    .replace(/&/g, "and")
    .replace(/['"`]/g, "")
    .replace(/[:;,.!?(){}\[\]|<>]/g, "")
    .replace(/[^a-zA-Z0-9]/g, "")   // ❗ remove EVERYTHING except letters+numbers
    .slice(0, 80);

  return s || "image";
}

// --- Inputs ---
const images = $node["Collect images URLS"].json.images;
const blog = $node["Writing Blog"].json.output || "";
const { h1, h2 } = extractHeadingsFromMarkdown(blog);
const getH2 = (n) => (h2 && h2.length >= n ? h2[n - 1] : "");

// --- Pull translations from Cleaning Image Prompts (by slot) ---
const translationsBySlot = {};
const cleaned = $items("Cleaning Image Prompts") || [];

for (const it of cleaned) {
  const j = it.json || {};
  if (!j.slot) continue;

  const t =
    (typeof j.translation_en === "string" && j.translation_en.trim()) || "";

  if (t) translationsBySlot[j.slot] = t;
}

function safeNameForSlot(slot, fallback) {
  const t = translationsBySlot[slot] || fallback || "image";
  return toHeaderSafeFilename(t);
}

// --- Build items ---
const map = [
  {
    key: "hero",
    slot: "hero",
    url: images.hero,
    filename_safe: safeNameForSlot("hero", "heroimage"),
    alt: h1 || "תמונה ראשית",
  },
  {
    key: "section_1",
    slot: "section_1",
    url: images.section_1,
    filename_safe: safeNameForSlot("section_1", "section1"),
    alt: getH2(4) || "תמונה",
  },
  {
    key: "section_2",
    slot: "section_2",
    url: images.section_2,
    filename_safe: safeNameForSlot("section_2", "section2"),
    alt: getH2(8) || "תמונה",
  },
  {
    key: "section_3",
    slot: "section_3",
    url: images.section_3,
    filename_safe: safeNameForSlot("section_3", "section3"),
    alt: getH2(12) || "תמונה",
  },
  {
    key: "section_4",
    slot: "section_4",
    url: images.section_4,
    filename_safe: safeNameForSlot("section_4", "section4"),
    alt: getH2(16) || "תמונה",
  },
];

// Output only items with URLs
return map
  .filter(x => !!x.url)
  .map(x => ({ json: x }));

function stripHtml(str) {
  return (str || "").replace(/<[^>]*>/g, "").trim();
}
function extractHeadingsFromMarkdown(md) {
  const lines = (md || "").split("\n").map(l => l.trim());
  let h1 = "";
  const h2 = [];
  for (const line of lines) {
    const m1 = line.match(/^#\s+(.+)$/);
    if (m1 && !h1) h1 = stripHtml(m1[1]);
    const m2 = line.match(/^##\s+(.+)$/);
    if (m2) h2.push(stripHtml(m2[1]));
  }
  return { h1, h2 };
}

const blog = $node["Writing Blog"].json.output || "";
const { h1, h2 } = extractHeadingsFromMarkdown(blog);
const H2 = (n) => h2[n - 1] || "";

const targets = {
  hero: h1 || "",
  section_1: H2(1) || "",
  section_2: H2(2) || "",
  section_3: H2(3) || "",
  section_4: H2(4) || "",
};

const wpItems = $input.all().map(i => i.json);

function wpUrl(m) {
  return (
    (m && typeof m.source_url === "string" && m.source_url) ||
    (m && m.guid && typeof m.guid.rendered === "string" && m.guid.rendered) ||
    ""
  );
}

function matchMediaToHeading(media, heading) {
  if (!heading) return false;
  const alt = (media.alt_text || "").trim();
  const title = (media.title && (media.title.raw || media.title.rendered) || "").trim();
  if (alt && alt === heading) return true;
  if (title && title === heading) return true;
  return false;
}

const structuredImages = {
  hero: null,
  section_1: null,
  section_2: null,
  section_3: null,
  section_4: null,
};

// 1) Match by alt_text/title
for (const media of wpItems) {
  const url = wpUrl(media);
  if (!url) continue;
  for (const key of Object.keys(structuredImages)) {
    if (structuredImages[key]) continue;
    if (matchMediaToHeading(media, targets[key])) {
      structuredImages[key] = { url, alt: targets[key] || (media.alt_text || "") };
    }
  }
}

// 2) Fallback by order
const remainingKeys = Object.keys(structuredImages).filter(k => !structuredImages[k]);
if (remainingKeys.length > 0) {
  const usedUrls = new Set(Object.values(structuredImages).filter(Boolean).map(x => x.url));
  const unused = wpItems
    .map(m => ({ m, url: wpUrl(m) }))
    .filter(x => x.url && !usedUrls.has(x.url));
  let idx = 0;
  for (const key of remainingKeys) {
    const pick = unused[idx++];
    if (!pick) break;
    structuredImages[key] = {
      url: pick.url,
      alt: targets[key] || (pick.m.alt_text || "")
    };
  }
}

// 3) Provide placeholder for any still-missing images
for (const key of Object.keys(structuredImages)) {
  if (!structuredImages[key]) {
    structuredImages[key] = { url: "", alt: targets[key] || "תמונה" };
  }
}

return [{ json: { images: structuredImages } }];

// Process response from Fetch Shopify Products
// The response may be JSON (Shopify) or HTML (Konimbo/protected sites)
// This node handles both cases gracefully

const rawData = $input.first().json;
const keyword = $('Grab New Cluster').first().json["Primary Keyword"] || "";
const keywords = keyword.toLowerCase().split(/\s+/);
const websiteUrl = $('Grab New Cluster').first().json.Website || "";

// Try to get products from the response
let allProducts = [];

try {
  // Check if we got a direct JSON response with products
  if (rawData.products && Array.isArray(rawData.products)) {
    allProducts = rawData.products;
  }
  // Check if the response is a text string (responseFormat: text)
  else if (typeof rawData.data === 'string') {
    const text = rawData.data.trim();
    // Check if it looks like JSON (starts with { or [)
    if (text.startsWith('{') || text.startsWith('[')) {
      const parsed = JSON.parse(text);
      allProducts = parsed.products || (Array.isArray(parsed) ? parsed : []);
    } else {
      // It's HTML or some other non-JSON response
      // This happens with Konimbo sites or sites with anti-bot protection
      allProducts = [];
    }
  }
  // Check if there's a body field with text content
  else if (typeof rawData.body === 'string') {
    const text = rawData.body.trim();
    if (text.startsWith('{') || text.startsWith('[')) {
      const parsed = JSON.parse(text);
      allProducts = parsed.products || (Array.isArray(parsed) ? parsed : []);
    } else {
      allProducts = [];
    }
  }
} catch (e) {
  // JSON parsing failed - response is not valid JSON (likely HTML)
  allProducts = [];
}

// If no products found, return empty array (workflow will continue without products)
if (!allProducts.length) {
  return [{ json: { title: "", url: "", price: "0", compare_at_price: null, main_image: "", product_type: "", tags: [], available: false, score: 0, _no_products: true } }];
}

// Score each product by keyword relevance
const scored = allProducts
  .filter(p => p.status === "active" || p.published_at)
  .map(p => {
    const text = [p.title, p.product_type, ...(p.tags || [])].join(" ").toLowerCase();
    let score = 0;
    for (const kw of keywords) {
      if (text.includes(kw)) score += 1;
    }
    const variant = (p.variants || [])[0] || {};
    const img = (p.images || [])[0] || {};
    return {
      title: p.title || "",
      url: "https://" + websiteUrl.replace(/^https?:\/\//, "") + "/products/" + p.handle,
      price: variant.price || "0",
      compare_at_price: variant.compare_at_price || null,
      main_image: img.src || "",
      product_type: p.product_type || "",
      tags: p.tags || [],
      available: variant.available !== false,
      score
    };
  })
  .filter(p => p.available && p.main_image)
  .sort((a, b) => b.score - a.score)
  .slice(0, 8);

return scored.length > 0
  ? scored.map(p => ({ json: p }))
  : [{ json: { title: "", url: "", price: "0", compare_at_price: null, main_image: "", product_type: "", tags: [], available: false, score: 0, _no_products: true } }];

// n8n Code node (JavaScript)
// Input: items[].json = your array objects (each has data.markdown + data.metadata)

function pickFirst(arr) {
  return Array.isArray(arr) ? arr[0] : arr;
}

function cleanText(s) {
  return (s || "")
    .replace(/\r/g, "")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function extractTitle(md) {
  const m = md.match(/^\#\s+(.+)$/m);
  return m ? m[1].trim() : "";
}

function extractPrice(md) {
  // match: "51.00 ₪" or "35.00 ₪–65.00 ₪"
  const m = md.match(/(\d+(?:\.\d+)?)\s*₪(?:\s*–\s*(\d+(?:\.\d+)?)\s*₪)?/);
  if (!m) return { price: "", price_min: null, price_max: null };
  const min = parseFloat(m[1]);
  const max = m[2] ? parseFloat(m[2]) : min;
  return { price: m[0].replace(/\s+/g, " ").trim(), price_min: min, price_max: max };
}

function extractSku(md) {
  const m = md.match(/מק["״']?ט:\s*([A-Z0-9\-]+)/i);
  return m ? m[1].trim() : "";
}

function extractImages(md) {
  // Capture markdown images: ![alt](url)
  const urls = [];
  const re = /!\[[^\]]*\]\((https?:\/\/[^)]+)\)/g;
  let match;
  while ((match = re.exec(md)) !== null) {
    const url = match[1];
    if (url.includes("cdn.userway.org/widgetapp/images/")) continue;
    urls.push(url);
  }

  // Prefer wp-content images
  const wp = urls.filter(u => u.includes("/wp-content/uploads/"));
  const main = wp[0] || urls[0] || "";

  // Gallery = unique wp images (exclude main)
  const gallery = [...new Set(wp.filter(u => u !== main))];

  return { main_image: main, gallery_images: gallery };
}

function stripNoise(md) {
  // Remove common noise blocks roughly (keep product content)
  const patterns = [
    /!\[Spinner:[^\]]*\]\([^)]+\)\n*/g,
    /!\[\]\(https:\/\/cdn\.userway\.org\/widgetapp\/images\/[^)]+\)\n*/g,
    /^40₪.*?\[סגור\]\([^)]+\)\n*/m,
    /^\s*\[דילוג לתוכן\]\([^)]+\)\n*/m,
    /##\s+מוצרים קשורים[\s\S]*$/m,        // cut everything after related products
    /עגלת קניות[\s\S]*$/m                 // or cut everything after cart widget
  ];

  let out = md;
  for (const p of patterns) out = out.replace(p, "");
  return cleanText(out);
}

function extractWeightDimensions(md) {
  // looks like:
  // | משקל | 0.5 ק"ג |
  // | מידות | 30 × 30 × 20 סנטימטרים |
  const weight = (md.match(/\|\s*משקל\s*\|\s*([^|]+)\|/m) || [])[1]?.trim() || "";
  const dimensions = (md.match(/\|\s*מידות\s*\|\s*([^|]+)\|/m) || [])[1]?.trim() || "";
  return { weight, dimensions };
}

function extractCategories(md) {
  // Categories appear as markdown links line before H1 in your samples
  // We'll take the last link-line before the first H1.
  const idx = md.search(/^\#\s+/m);
  if (idx === -1) return [];
  const before = md.slice(0, idx);
  const linkLine = before.trim().split("\n").reverse().find(l => l.includes("](https://www.galoz.co.il/product-category/"));
  if (!linkLine) return [];
  const cats = [];
  const re = /\[([^\]]+)\]\((https?:\/\/[^)]+product-category[^)]+)\)/g;
  let m;
  while ((m = re.exec(linkLine)) !== null) cats.push(m[1].trim());
  return cats;
}

return items.map((item) => {
  const mdRaw = item.json?.data?.markdown || "";
  const meta = item.json?.data?.metadata || {};

  const md = stripNoise(mdRaw);

  const title = extractTitle(md);
  const priceObj = extractPrice(md);
  const sku = extractSku(md);
  const imgs = extractImages(md);
  const wd = extractWeightDimensions(md);
  const categories = extractCategories(md);

  return {
    json: {
      url: meta.url || meta.ogUrl || "",
      title,
      ...priceObj,
      currency: "ILS",
      sku,
      categories,
      ...imgs,
      short_description: "", // optional: add if you decide where to slice it from md
      variations: [],        // optional: parse if needed later
      weight: wd.weight,
      dimensions: wd.dimensions,
      language: meta.language || "he-IL",
      og_title: meta["og:title"] || meta.ogTitle || "",
      og_description: meta["og:description"] || meta.ogDescription || meta.description || "",
      modified_time: meta.modifiedTime || meta["article:modified_time"] || ""
    }
  };
});

// Aggregate products from Gets the product pages
// Input: items from Gets the product pages (each is a product)
const products = $input.all().map(i => i.json);

return [
  {
    json: { products },
    pairedItem: $input.all().map((_, index) => ({ item: index })),
  },
];

/**
 * n8n Code node (JavaScript)
 * Input: item.json.output (string) OR item.json.text (string) OR item.json (string)
 * Output: columns ready for Google Sheets mapping
 */

function pickText(item) {
  return (
    item.json.output ??
    item.json.text ??
    item.json.result ??
    (typeof item.json === 'string' ? item.json : null) ??
    ''
  );
}

function normalize(s) {
  return (s || '')
    .replace(/\r\n/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    .trim();
}

function extractSection(fullText, label) {
  // Matches: 🔹 LinkedIn: ... until next 🔹 or end
  const re = new RegExp(
    String.raw`(?:^|\n)\s*(?:🔹\s*)?${label}\s*:\s*([\s\S]*?)(?=\n\s*(?:🔹\s*)?(?:LinkedIn|Facebook|Instagram|X)\s*:|\s*$)`,
    'i'
  );
  const m = fullText.match(re);
  return normalize(m ? m[1] : '');
}

function makePreview(s, max = 120) {
  const t = normalize(s).replace(/\n+/g, ' ');
  return t.length > max ? t.slice(0, max - 1) + '…' : t;
}

const out = [];

for (const item of $input.all()) {
  const raw = normalize(pickText(item));

  const linkedin = extractSection(raw, 'LinkedIn');
  const facebook = extractSection(raw, 'Facebook');
  const instagram = extractSection(raw, 'Instagram');
  const xpost = extractSection(raw, 'X');

  out.push({
    json: {
      // These keys should match your Google Sheet columns (recommended):
      LinkedIn: linkedin,
      Facebook: facebook,
      Instagram: instagram,
      X: xpost,

      // Optional useful fields:
      LinkedIn_Preview: makePreview(linkedin),
      Facebook_Preview: makePreview(facebook),
      Instagram_Preview: makePreview(instagram),
      X_Preview: makePreview(xpost),

      // Store original text too (optional):
      Raw_Output: raw,
    },
  });
}

return out;

