// Extract the taskId from the kie.ai createTask response
// and initialize polling state (attempts + start timestamp)
const response = $json;
const taskId = response.data?.taskId || response.data?.recordId || null;

if (!taskId) {
  throw new Error('No taskId found in kie.ai response: ' + JSON.stringify(response));
}

return [{
  json: {
    taskId: taskId,
    status: 'pending',
    attempts: 0,
    startedAt: Date.now(),
    maxElapsedMs: 5 * 60 * 1000   // give each image up to 5 minutes
  }
}];
